// jwt-mini: HS256 sign/verify. Vendored equivalent, MIT, dependency-free
// except for WebCrypto + TextEncoder which are spec globals.
//
// JWT format: <base64url(header)>.<base64url(payload)>.<base64url(sig)>
// HS256: HMAC-SHA-256 over `header.payload` (the signing input).

const encoder = new TextEncoder();
const decoder = new TextDecoder();

// base64url helpers — base64 without padding, URL-safe alphabet.
function base64urlEncode(bytes) {
    // Standard btoa works on string of code-points 0-255; convert byte
    // array to that string form first.
    let bin = "";
    for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
    return btoa(bin).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

function base64urlDecode(s) {
    s = s.replace(/-/g, "+").replace(/_/g, "/");
    while (s.length % 4) s += "=";
    const bin = atob(s);
    const out = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
    return out;
}

async function importHmacKey(secret, usages) {
    const keyBytes = typeof secret === "string" ? encoder.encode(secret) : secret;
    return crypto.subtle.importKey(
        "raw", keyBytes,
        { name: "HMAC", hash: "SHA-256" },
        false, usages,
    );
}

export async function sign(payload, secret) {
    const header = { alg: "HS256", typ: "JWT" };
    const headerB64 = base64urlEncode(encoder.encode(JSON.stringify(header)));
    const payloadB64 = base64urlEncode(encoder.encode(JSON.stringify(payload)));
    const signingInput = headerB64 + "." + payloadB64;
    const key = await importHmacKey(secret, ["sign"]);
    const sigBytes = new Uint8Array(
        await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput)));
    const sigB64 = base64urlEncode(sigBytes);
    return signingInput + "." + sigB64;
}

export async function verify(token, secret) {
    const parts = token.split(".");
    if (parts.length !== 3) {
        return { valid: false, error: "malformed token" };
    }
    const [headerB64, payloadB64, sigB64] = parts;
    let header, payload;
    try {
        header = JSON.parse(decoder.decode(base64urlDecode(headerB64)));
        payload = JSON.parse(decoder.decode(base64urlDecode(payloadB64)));
    } catch (e) {
        return { valid: false, error: "invalid base64 or JSON" };
    }
    if (header.alg !== "HS256") {
        return { valid: false, error: "unsupported alg: " + header.alg };
    }
    const signingInput = headerB64 + "." + payloadB64;
    const sigBytes = base64urlDecode(sigB64);
    const key = await importHmacKey(secret, ["verify"]);
    const ok = await crypto.subtle.verify("HMAC", key, sigBytes, encoder.encode(signingInput));
    if (!ok) return { valid: false, error: "signature mismatch" };
    return { valid: true, header, payload };
}

export default { sign, verify };
